    for (String t:tokens) {
        switch(t) {
            case "+": stack.push(stack.pop()+stack.pop()); break;
            case "*": stack.push(stack.pop()*stack.pop()); break;
            case "-": { int b=stack.pop(),a=stack.pop(); stack.push(a-b); } break;
            case "/": { int b=stack.pop(),a=stack.pop(); stack.push(a/b); } break;
