            for (int[] d:dirs) { int r=c[0]+d[0],col=c[1]+d[1]; if (r>=0&&r<m&&col>=0&&col<n&&grid[r][col]==1) { grid[r][col]=2; fresh--; q.offer(new int[]{r,col}); } }
