    while (top<=bot && left<=right) {
        for (int i=left;i<=right;i++) res.add(matrix[top][i]); top++;
        for (int i=top;i<=bot;i++) res.add(matrix[i][right]); right--;
        if (top<=bot) for (int i=right;i>=left;i--) res.add(matrix[bot][i]); bot--;
