private void bt(List<List<Integer>> res, List<Integer> curr, int[] nums, int start) {
    res.add(new ArrayList<>(curr));
    for (int i=start;i<nums.length;i++) { curr.add(nums[i]); bt(res,curr,nums,i+1); curr.remove(curr.size()-1); }
}

public List<Integer> rightSideView(TreeNode root) {
    List<Integer> res=new ArrayList<>();
    if (root==null) return res;
    Queue<TreeNode> q=new LinkedList<>(); q.offer(root);
    while (!q.isEmpty()) {
        int sz=q.size();
        for (int i=0;i<sz;i++) { TreeNode n=q.poll(); if (i==sz-1) res.add(n.val); if (n.left!=null) q.offer(n.left); if (n.right!=null) q.offer(n.right); }
    }
    return res;
}

public String longestPalindrome(String s) {
    int start=0, maxLen=1;
    for (int i=0;i<s.length();i++) {
        int l1=expand(s,i,i), l2=expand(s,i,i+1);
        int len=Math.max(l1,l2);
        if (len>maxLen) { maxLen=len; start=i-(len-1)/2; }
    }
    return s.substring(start,start+maxLen);
}
private int expand(String s, int l, int r) {
    while (l>=0&&r<s.length()&&s.charAt(l)==s.charAt(r)) { l--;r++; }
    return r-l-1;
}

public int uniquePaths(int m, int n) {
    int[] dp=new int[n]; Arrays.fill(dp,1);
    for (int i=1;i<m;i++) for (int j=1;j<n;j++) dp[j]+=dp[j-1];
    return dp[n-1];
}

int preIdx=0;
public TreeNode buildTree(int[] pre, int[] in) {
    Map<Integer,Integer> inMap=new HashMap<>();
    for (int i=0;i<in.length;i++) inMap.put(in[i],i);
    return build(pre, 0, in.length-1, inMap);
}
private TreeNode build(int[] pre, int inL, int inR, Map<Integer,Integer> inMap) {
    if (inL>inR) return null;
    int rootVal=pre[preIdx++];
    TreeNode root=new TreeNode(rootVal);
    int inIdx=inMap.get(rootVal);
    root.left=build(pre,inL,inIdx-1,inMap);
    root.right=build(pre,inIdx+1,inR,inMap);
    return root;
}

public int maxArea(int[] height) {
    int lo=0,hi=height.length-1,max=0;
    while (lo<hi) {
        max=Math.max(max, Math.min(height[lo],height[hi])*(hi-lo));
        if (height[lo]<height[hi]) lo++; else hi--;
    }
    return max;
}

public List<String> letterCombinations(String digits) {
    if (digits.isEmpty()) return new ArrayList<>();
    String[] map={"","","abc","def","ghi","jkl","mno","pqrs","tuv","wxyz"};
    List<String> res=new ArrayList<>();
    bt(res,new StringBuilder(),digits,map,0);
    return res;
}
private void bt(List<String> res, StringBuilder curr, String digits, String[] map, int idx) {
    if (idx==digits.length()) { res.add(curr.toString()); return; }
    for (char c:map[digits.charAt(idx)-'0'].toCharArray()) { curr.append(c); bt(res,curr,digits,map,idx+1); curr.deleteCharAt(curr.length()-1); }
}

public boolean exist(char[][] board, String word) {
    for (int i=0;i<board.length;i++) for (int j=0;j<board[0].length;j++) if (dfs(board,word,i,j,0)) return true;
    return false;
}
private boolean dfs(char[][] b, String w, int r, int c, int idx) {
    if (idx==w.length()) return true;
    if (r<0||r>=b.length||c<0||c>=b[0].length||b[r][c]!=w.charAt(idx)) return false;
    char tmp=b[r][c]; b[r][c]='#';
    boolean found=dfs(b,w,r+1,c,idx+1)||dfs(b,w,r-1,c,idx+1)||dfs(b,w,r,c+1,idx+1)||dfs(b,w,r,c-1,idx+1);
    b[r][c]=tmp; return found;
}

public List<Integer> findAnagrams(String s, String p) {
    List<Integer> res=new ArrayList<>();
    if (s.length()<p.length()) return res;
    int[] pC=new int[26], wC=new int[26], w=new int[]{p.length()};
    for (char c:p.toCharArray()) pC[c-'a']++;
    for (int i=0;i<p.length();i++) wC[s.charAt(i)-'a']++;
    if (Arrays.equals(pC,wC)) res.add(0);
    for (int i=p.length();i<s.length();i++) {
        wC[s.charAt(i)-'a']++; wC[s.charAt(i-p.length())-'a']--;
        if (Arrays.equals(pC,wC)) res.add(i-p.length()+1);
    }
    return res;
}

public List<Integer> findMinHeightTrees(int n, int[][] edges) {
    if (n==1) return List.of(0);
    List<Set<Integer>> adj=new ArrayList<>();
    for (int i=0;i<n;i++) adj.add(new HashSet<>());
    for (int[] e:edges) { adj.get(e[0]).add(e[1]); adj.get(e[1]).add(e[0]); }
    List<Integer> leaves=new ArrayList<>();
    for (int i=0;i<n;i++) if (adj.get(i).size()==1) leaves.add(i);
    int rem=n;
    while (rem>2) {
        rem-=leaves.size();
        List<Integer> newLeaves=new ArrayList<>();
        for (int leaf:leaves) { int nb=adj.get(leaf).iterator().next(); adj.get(nb).remove(leaf); if (adj.get(nb).size()==1) newLeaves.add(nb); }
        leaves=newLeaves;
    }
    return leaves;
}

public int leastInterval(char[] tasks, int n) {
    int[] freq=new int[26];
    for (char t:tasks) freq[t-'A']++;
    Arrays.sort(freq);
    int maxF=freq[25], maxCnt=0;
    for (int f:freq) if (f==maxF) maxCnt++;
    return Math.max(tasks.length, (maxF-1)*(n+1)+maxCnt);
}

class LRUCache {
    class Node { int key,val; Node prev,next; Node(int k,int v){key=k;val=v;} }
    Map<Integer,Node> map; int cap;
    Node head,tail;
    LRUCache(int capacity) { cap=capacity; map=new HashMap<>(); head=new Node(0,0); tail=new Node(0,0); head.next=tail; tail.prev=head; }
    public int get(int key) { if (!map.containsKey(key)) return -1; moveToFront(map.get(key)); return map.get(key).val; }
    public void put(int key, int value) {
        if (map.containsKey(key)) { map.get(key).val=value; moveToFront(map.get(key)); }
        else { if (map.size()==cap) { map.remove(tail.prev.key); remove(tail.prev); } Node n=new Node(key,value); addFront(n); map.put(key,n); }
    }
    void remove(Node n){ n.prev.next=n.next; n.next.prev=n.prev; }
    void addFront(Node n){ n.next=head.next; n.prev=head; head.next.prev=n; head.next=n; }
    void moveToFront(Node n){ remove(n); addFront(n); }
}

public int kthSmallest(TreeNode root, int k) {
    Deque<TreeNode> stack=new ArrayDeque<>();
    TreeNode curr=root;
    while (curr!=null||!stack.isEmpty()) {
        while (curr!=null) { stack.push(curr); curr=curr.left; }
        curr=stack.pop();
        if (--k==0) return curr.val;
        curr=curr.right;
    }
    return -1;
}

public String minWindow(String s, String t) {
    Map<Character,Integer> need=new HashMap<>(), win=new HashMap<>();
    for (char c:t.toCharArray()) need.merge(c,1,Integer::sum);
    int left=0,right=0,valid=0,minLen=Integer.MAX_VALUE,start=0;
    while (right<s.length()) {
        char rc=s.charAt(right++);
        if (need.containsKey(rc)) { win.merge(rc,1,Integer::sum); if (win.get(rc).equals(need.get(rc))) valid++; }
        while (valid==need.size()) {
            if (right-left<minLen) { minLen=right-left; start=left; }
            char lc=s.charAt(left++);
            if (need.containsKey(lc)) { if (win.get(lc).equals(need.get(lc))) valid--; win.merge(lc,-1,Integer::sum); }
        }
    }
    return minLen==Integer.MAX_VALUE ? "" : s.substring(start,start+minLen);
}

public class Codec {
    public String serialize(TreeNode root) {
        if (root==null) return "";
        StringBuilder sb=new StringBuilder();
        Queue<TreeNode> q=new LinkedList<>(); q.offer(root);
        while (!q.isEmpty()) { TreeNode n=q.poll(); if (n==null){sb.append("null,");continue;} sb.append(n.val).append(","); q.offer(n.left); q.offer(n.right); }
        return sb.toString();
    }
    public TreeNode deserialize(String data) {
        if (data.isEmpty()) return null;
        String[] vals=data.split(",");
        TreeNode root=new TreeNode(Integer.parseInt(vals[0]));
        Queue<TreeNode> q=new LinkedList<>(); q.offer(root);
        for (int i=1;i<vals.length;) {
            TreeNode n=q.poll();
            if (!vals[i].equals("null")) { n.left=new TreeNode(Integer.parseInt(vals[i])); q.offer(n.left); } i++;
            if (i<vals.length&&!vals[i].equals("null")) { n.right=new TreeNode(Integer.parseInt(vals[i])); q.offer(n.right); } i++;
        }
        return root;
    }
}

public int trap(int[] height) {
    int lo=0,hi=height.length-1,maxL=0,maxR=0,water=0;
    while (lo<hi) {
        if (height[lo]<=height[hi]) {
            if (height[lo]>=maxL) maxL=height[lo]; else water+=maxL-height[lo]; lo++;
        } else {
            if (height[hi]>=maxR) maxR=height[hi]; else water+=maxR-height[hi]; hi--;
        }
    }
    return water;
}

class MedianFinder {
    PriorityQueue<Integer> lo=new PriorityQueue<>(Collections.reverseOrder()); // max-heap
    PriorityQueue<Integer> hi=new PriorityQueue<>(); // min-heap
    public void addNum(int num) { lo.offer(num); hi.offer(lo.poll()); if (lo.size()<hi.size()) lo.offer(hi.poll()); }
    public double findMedian() { return lo.size()>hi.size() ? lo.peek() : (lo.peek()+hi.peek())/2.0; }
}

public int ladderLength(String begin, String end, List<String> wordList) {
    Set<String> wordSet=new HashSet<>(wordList);
    if (!wordSet.contains(end)) return 0;
    Queue<String> q=new LinkedList<>(); q.offer(begin); wordSet.remove(begin);
    int steps=1;
    while (!q.isEmpty()) {
        steps++;
        for (int sz=q.size();sz>0;sz--) {
            char[] word=q.poll().toCharArray();
            for (int j=0;j<word.length;j++) {
                char orig=word[j];
                for (char c='a';c<='z';c++) {
                    if (c==orig) continue;
                    word[j]=c; String next=new String(word);
                    if (next.equals(end)) return steps;
                    if (wordSet.contains(next)) { q.offer(next); wordSet.remove(next); }
                }
                word[j]=orig;
            }
        }
    }
    return 0;
}

public int calculate(String s) {
    Deque<Integer> stack=new ArrayDeque<>();
    int result=0, num=0, sign=1;
    for (char c:s.toCharArray()) {
        if (Character.isDigit(c)) num=num*10+(c-'0');
        else if (c=='+') { result+=sign*num; num=0; sign=1; }
        else if (c=='-') { result+=sign*num; num=0; sign=-1; }
        else if (c=='(') { stack.push(result); stack.push(sign); result=0; sign=1; }
        else if (c==')') { result+=sign*num; num=0; result*=stack.pop(); result+=stack.pop(); }
    }
    return result+sign*num;
}

public int jobScheduling(int[] start, int[] end, int[] profit) {
    int n=start.length;
    int[][] jobs=new int[n][3];
    for (int i=0;i<n;i++) jobs[i]=new int[]{end[i],start[i],profit[i]};
    Arrays.sort(jobs,(a,b)->a[0]-b[0]);
    int[] dp=new int[n+1];
    for (int i=1;i<=n;i++) {
        int lo=0,hi=i-1;
        while (lo<hi) { int mid=(lo+hi+1)/2; if (jobs[mid-1][0]<=jobs[i-1][1]) lo=mid; else hi=mid-1; }
        dp[i]=Math.max(dp[i-1], dp[lo]+jobs[i-1][2]);
    }
    return dp[n];
}

public ListNode mergeKLists(ListNode[] lists) {
    PriorityQueue<ListNode> pq=new PriorityQueue<>((a,b)->a.val-b.val);
    for (ListNode n:lists) if (n!=null) pq.offer(n);
    ListNode dummy=new ListNode(0), curr=dummy;
    while (!pq.isEmpty()) {
        ListNode n=pq.poll(); curr.next=n; curr=curr.next;
        if (n.next!=null) pq.offer(n.next);
    }
    return dummy.next;
}

public int largestRectangleArea(int[] heights) {
    Deque<Integer> stack=new ArrayDeque<>();
    int maxArea=0;
    for (int i=0;i<=heights.length;i++) {
        int h=(i==heights.length)?0:heights[i];
        while (!stack.isEmpty()&&h<heights[stack.peek()]) {
            int height=heights[stack.pop()];
            int width=stack.isEmpty()?i:i-stack.peek()-1;
            maxArea=Math.max(maxArea,height*width);
        }
        stack.push(i);
    }
    return maxArea;
}
